"""Local HA verification script tests."""

from __future__ import annotations

from pathlib import Path

from scripts.verify_local_ha import (
    REQUIRED_RUNTIME_MODULES,
    SOURCE_COMPONENT_ROOT,
    VerificationReport,
    forbidden_install_paths,
    parse_domain_counts,
    runtime_diff,
    verify_required_modules,
)


def test_runtime_diff_ignores_ha_generated_cache(tmp_path: Path) -> None:
    """Runtime comparison should ignore pycache generated by HA."""
    source = tmp_path / "source"
    installed = tmp_path / "installed"
    source.mkdir()
    installed.mkdir()
    (source / "__init__.py").write_text("ok = True\n", encoding="utf-8")
    (installed / "__init__.py").write_text("ok = True\n", encoding="utf-8")
    cache = installed / "__pycache__"
    cache.mkdir()
    (cache / "__init__.cpython-314.pyc").write_bytes(b"cache")

    diff = runtime_diff(source, installed)

    assert diff.ok


def test_runtime_diff_detects_changed_runtime_file(tmp_path: Path) -> None:
    """Runtime comparison should detect installed source drift."""
    source = tmp_path / "source"
    installed = tmp_path / "installed"
    source.mkdir()
    installed.mkdir()
    (source / "manifest.json").write_text('{"version": "1"}', encoding="utf-8")
    (installed / "manifest.json").write_text('{"version": "2"}', encoding="utf-8")

    diff = runtime_diff(source, installed)

    assert diff.changed == ("manifest.json",)


def test_required_modules_fail_for_missing_support_module(tmp_path: Path) -> None:
    """本地 HA 验证应发现缺失的关键支持模块."""
    install_root = tmp_path / "config" / "custom_components" / "yeelight_pro"
    install_root.mkdir(parents=True)
    report = VerificationReport()

    verify_required_modules(
        install_root,
        report,
        modules=("custom_components.yeelight_pro.missing_support",),
    )

    assert not report.ok
    assert any("missing_support" in failure for failure in report.failures)


