def test_forbidden_install_paths_rejects_tests_and_text(tmp_path: Path) -> None:
    """Installed HA target must not retain release-excluded files."""
    install = tmp_path / "yeelight_pro"
    tests_dir = install / "tests"
    tests_dir.mkdir(parents=True)
    (tests_dir / "test_old.py").write_text("", encoding="utf-8")
    (install / "text.py").write_text("", encoding="utf-8")

    assert forbidden_install_paths(install) == ["tests", "tests/test_old.py", "text.py"]


def test_parse_domain_counts() -> None:
    """Expected entity-domain counts should be CLI-overridable."""
    assert parse_domain_counts("light=2,switch=1") == {"light": 2, "switch": 1}


def test_source_component_root_exists() -> None:
    """The verification script should point at the packaged source component."""
    assert SOURCE_COMPONENT_ROOT.exists()
